package tests;
import base.BaseTest;import models.LoginUser;import org.testng.Assert;import org.testng.annotations.Test;import pages.*;import utils.SoftAssertManager;import static org.assertj.core.api.Assertions.assertThat;
public class LoginTest extends BaseTest { @Test(dataProvider="validLoginJson", dataProviderClass=data.LoginDataProvider.class, groups={"smoke","regression"}) public void userCanLogin(LoginUser user){ LoginPage login=new LoginPage(driver()); DashboardPage dash=login.loginAs(user.username(),user.password()); assertThat(dash.heading()).as("Dashboard heading").isEqualTo(user.expectedHeading()); Assert.assertTrue(dash.cartVisible(),"Cart should be visible after login"); SoftAssertManager.get().assertTrue(driver().getCurrentUrl().contains("inventory"),"URL should contain inventory"); SoftAssertManager.get().assertEquals(dash.productCount(),6,"Product count"); SoftAssertManager.assertAll(); } }
